export function getProofExplanation(proof: VisualProof): ProofExplanation | null {
  return proofExplanations[`${proof.categorySlug}/${proof.slug}`] ?? null;
}

export function buildProofNarration(proof: VisualProof, explanation: ProofExplanation) {
  return [
    proof.title,
    explanation.plainLanguage,
    explanation.whyItWorks,
    `Watch for: ${explanation.watchFor.join("; ")}.`,
    `Common misconception: ${explanation.commonMisconception}`,
    `Teacher prompt: ${explanation.teacherPrompt}`,
  ].join(" ");
}
